import React from 'react'
import { UpcomingEventContent } from '../../contexts/types'
import SectionLockControl from './SectionLockControl'
import './UpcomingEventEditor.css'

interface UpcomingEventEditorProps {
    data: UpcomingEventContent
    onChange: (data: Partial<UpcomingEventContent>) => void
}

const UpcomingEventEditor: React.FC<UpcomingEventEditorProps> = ({ data, onChange }) => {

    // Check if data is undefined and provide default if needed, though it should be populated by context
    if (!data) return <div>Loading...</div>

    const updateField = (field: keyof UpcomingEventContent, value: any) => {
        onChange({ [field]: value })
    }

    return (
        <div className="editor-container">
            <div className="editor-header-row">
                <h3>Upcoming Event Configuration</h3>
                <div className="editor-header-actions">
                    <div className={`status-badge ${data.enabled ? 'active' : 'hidden'}`}>
                        {data.enabled ? 'ACTIVE' : 'HIDDEN'}
                    </div>
                    <div className="header-toggle-container" title={data.enabled ? 'Hide Section' : 'Show Section'}>
                        <label className="toggle-switch small">
                            <input
                                type="checkbox"
                                checked={data.enabled}
                                onChange={(e) => updateField('enabled', e.target.checked)}
                                disabled={data.locked}
                            />
                            <span className="toggle-slider"></span>
                        </label>
                    </div>
                    <SectionLockControl
                        locked={data.locked}
                        onToggle={(locked: boolean) => onChange({ locked })}
                    />
                </div>
            </div>

            <div className={`editor-content ${data.locked ? 'locked' : ''}`}>
                <div className="editor-section">
                    <div className="editor-grid-2">
                        <div className="form-group">
                            <label>Section Label</label>
                            <input
                                type="text"
                                value={data.label}
                                onChange={(e) => updateField('label', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. Sắp diễn ra:"
                            />
                        </div>
                        <div className="form-group">
                            <label>Event Title</label>
                            <input
                                type="text"
                                value={data.title}
                                onChange={(e) => updateField('title', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. Pháp hội Dược Sư"
                            />
                        </div>
                    </div>
                </div>

                <div className="editor-section">
                    <h4>California Schedule</h4>
                    <div className="editor-grid-2">
                        <div className="form-group">
                            <label>Location Label</label>
                            <input
                                type="text"
                                value={data.californiaLabel}
                                onChange={(e) => updateField('californiaLabel', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. California:"
                            />
                        </div>
                        <div className="form-group">
                            <label>Venue / Type</label>
                            <input
                                type="text"
                                value={data.californiaSubLabel}
                                onChange={(e) => updateField('californiaSubLabel', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. Trực tiếp tại BĐPQ"
                            />
                        </div>
                        <div className="form-group full-width">
                            <label>Date/Time Display</label>
                            <input
                                type="text"
                                value={data.californiaDate}
                                onChange={(e) => updateField('californiaDate', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. 26/02/2026"
                            />
                        </div>
                    </div>
                </div>

                <div className="editor-section">
                    <h4>Vietnam Schedule</h4>
                    <div className="editor-grid-2">
                        <div className="form-group">
                            <label>Location Label</label>
                            <input
                                type="text"
                                value={data.vietnamLabel}
                                onChange={(e) => updateField('vietnamLabel', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. Việt Nam:"
                            />
                        </div>
                        <div className="form-group">
                            <label>Venue / Type</label>
                            <input
                                type="text"
                                value={data.vietnamSubLabel}
                                onChange={(e) => updateField('vietnamSubLabel', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. Online Zoom/Youtube"
                            />
                        </div>
                        <div className="form-group full-width">
                            <label>Date/Time Display</label>
                            <input
                                type="text"
                                value={data.vietnamDate}
                                onChange={(e) => updateField('vietnamDate', e.target.value)}
                                disabled={data.locked || !data.enabled}
                                placeholder="e.g. 27/02/2026"
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default UpcomingEventEditor
