import React, { useState } from 'react'
import './SubmissionsEditor.css'

interface Submission {
    id: string;
    date: string;
    email: string;
    formName: string;
    message: string;
}

const sampleSubmissions: Submission[] = [
    {
        id: "sub_001",
        date: "2026-02-05",
        email: "ali@example.com",
        formName: "Contact Form",
        message: "Hello, I would like to inquire about your services and pricing details. I am particularly interested in the advanced meditation course and would like to know the schedule for the upcoming months. Please let me know if there are any prerequisites for joining."
    },
    {
        id: "sub_002",
        date: "2026-02-04",
        email: "sara@example.com",
        formName: "Booking Form",
        message: "Can you please confirm availability for next week? I am looking to book a session for our group of 15 people. We are interested in a half-day retreat covering the basics of mindfulness."
    },
    {
        id: "sub_003",
        date: "2026-02-03",
        email: "mohammad@example.com",
        formName: "Feedback Form",
        message: "Overall the experience was good, but I think the interface could be improved. Some buttons are hard to find on mobile devices, and the loading speed seems a bit slow at times."
    }
];

const SubmissionsEditor: React.FC = () => {
    const [selectedId, setSelectedId] = useState<string | null>(null);

    const selectedSubmission = sampleSubmissions.find(s => s.id === selectedId);

    const truncateMessage = (msg: string) => {
        if (msg.length <= 70) return msg;
        return msg.substring(0, 70) + "...";
    };

    const formatDate = (dateStr: string) => {
        const date = new Date(dateStr);
        return date.toLocaleDateString('en-GB', {
            day: '2-digit',
            month: 'short',
            year: 'numeric'
        });
    }

    if (selectedSubmission) {
        return (
            <div className="submissions-editor">
                <div className="editor-header-title">
                    <button className="btn-back" onClick={() => setSelectedId(null)}>
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <line x1="19" y1="12" x2="5" y2="12"></line>
                            <polyline points="12 19 5 12 12 5"></polyline>
                        </svg>
                        Back to List
                    </button>
                    <h2>Submission Details</h2>
                </div>

                <div className="submission-detail-container">
                    <div className="detail-header">
                        <span className="col-form-name">{selectedSubmission.formName}</span>
                        <span className="col-date">{formatDate(selectedSubmission.date)}</span>
                    </div>
                    <div className="detail-content">
                        <div className="detail-info-grid">
                            <div className="info-item">
                                <span className="info-label">Form Name</span>
                                <span className="info-value">{selectedSubmission.formName}</span>
                            </div>
                            <div className="info-item">
                                <span className="info-label">Date Submitted</span>
                                <span className="info-value">{formatDate(selectedSubmission.date)}</span>
                            </div>
                            <div className="info-item">
                                <span className="info-label">Email Address</span>
                                <span className="info-value">{selectedSubmission.email}</span>
                            </div>
                        </div>

                        <div className="detail-message-section">
                            <span className="detail-message-label">Message</span>
                            <div className="detail-message-body">
                                {selectedSubmission.message}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="submissions-editor">
            <div className="editor-header-title">
                <h2>Form Submissions</h2>
                <p className="editor-subtitle">Review and manage all incoming form responses</p>
            </div>

            <div className="submissions-table-container">
                <table className="submissions-table">
                    <thead>
                        <tr>
                            <th style={{ width: '150px' }}>Date</th>
                            <th style={{ width: '250px' }}>Email</th>
                            <th style={{ width: '150px' }}>Form Name</th>
                            <th>Message Preview</th>
                        </tr>
                    </thead>
                    <tbody>
                        {sampleSubmissions.sort((a, b) => b.date.localeCompare(a.date)).map((sub) => (
                            <tr key={sub.id} onClick={() => setSelectedId(sub.id)}>
                                <td className="col-date" data-label="Date">{formatDate(sub.date)}</td>
                                <td className="col-email" data-label="Email">{sub.email}</td>
                                <td data-label="Form">
                                    <span className="col-form-name">{sub.formName}</span>
                                </td>
                                <td className="col-message" data-label="Message">{truncateMessage(sub.message)}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {sampleSubmissions.length === 0 && (
                    <div className="empty-state">
                        <p>No submissions found.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default SubmissionsEditor;
