import React, { useState } from 'react'
import './FooterEditor.css'
import { FooterContent, FooterLinkItem } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import SectionLockControl from './SectionLockControl'

type FooterEditorProps = {
    data: FooterContent
    onChange: (data: Partial<FooterContent>) => void
}

const FooterEditor: React.FC<FooterEditorProps> = ({ data, onChange }) => {
    const [activeTab, setActiveTab] = useState<'general' | 'contact' | 'links' | 'social'>('general')

    const updateContact = (updates: Partial<FooterContent['contact']>) => {
        onChange({ contact: { ...data.contact, ...updates } })
    }

    const updateSocial = (updates: Partial<FooterContent['social']>) => {
        onChange({ social: { ...data.social, ...updates } })
    }

    const updateQuickLink = (id: string, updates: Partial<FooterLinkItem>) => {
        const updatedItems = data.quickLinks.items.map(item =>
            item.id === id ? { ...item, ...updates } : item
        )
        onChange({ quickLinks: { ...data.quickLinks, items: updatedItems } })
    }

    const addQuickLink = () => {
        const newItem: FooterLinkItem = {
            id: `ql-${Date.now()}`,
            label: 'New Link',
            href: '#'
        }
        onChange({ quickLinks: { ...data.quickLinks, items: [...data.quickLinks.items, newItem] } })
    }

    const removeQuickLink = (id: string) => {
        const updatedItems = data.quickLinks.items.filter(item => item.id !== id)
        onChange({ quickLinks: { ...data.quickLinks, items: updatedItems } })
    }

    return (
        <div className="footer-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Footer Content</h2>
                    <SectionLockControl
                        locked={data.locked}
                        onToggle={(newLocked) => onChange({ locked: newLocked })}
                    />
                </div>
                <p className="editor-subtitle">Manage global footer information and links</p>
            </div>

            <div className="editor-tabs">
                <button
                    className={`tab-btn ${activeTab === 'general' ? 'active' : ''}`}
                    onClick={() => setActiveTab('general')}
                >
                    General
                </button>
                <button
                    className={`tab-btn ${activeTab === 'contact' ? 'active' : ''}`}
                    onClick={() => setActiveTab('contact')}
                >
                    Contact
                </button>
                <button
                    className={`tab-btn ${activeTab === 'links' ? 'active' : ''}`}
                    onClick={() => setActiveTab('links')}
                >
                    Quick Links
                </button>
                <button
                    className={`tab-btn ${activeTab === 'social' ? 'active' : ''}`}
                    onClick={() => setActiveTab('social')}
                >
                    Social
                </button>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                {activeTab === 'general' && (
                    <div className="tab-content fadeIn">
                        <div className="form-group">
                            <label className="form-label">Desktop Title</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.titleDesktop}
                                onChange={(e) => onChange({ titleDesktop: e.target.value })}
                            />
                        </div>
                        <div className="form-group">
                            <label className="form-label">Mobile Title</label>
                            <textarea
                                className="form-input"
                                rows={2}
                                value={data.titleMobile}
                                onChange={(e) => onChange({ titleMobile: e.target.value })}
                                placeholder="Use \n for line breaks"
                            />
                        </div>
                        <div className="form-grid-2">
                            <ImageEditor
                                label="Footer Background"
                                value={data.backgroundImage}
                                onChange={(url) => onChange({ backgroundImage: url })}
                            />
                            <ImageEditor
                                label="Footer Logo"
                                value={data.logoImage}
                                onChange={(url) => onChange({ logoImage: url })}
                            />
                        </div>
                        <div className="form-group">
                            <label className="form-label">Logo Alt Text</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.logoAlt}
                                onChange={(e) => onChange({ logoAlt: e.target.value })}
                            />
                        </div>
                        <div className="form-group">
                            <label className="form-label">Copyright Text</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.copyright}
                                onChange={(e) => onChange({ copyright: e.target.value })}
                            />
                        </div>

                    </div>
                )}

                {activeTab === 'contact' && (
                    <div className="tab-content fadeIn">
                        <div className="form-group">
                            <label className="form-label">Section Title</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.contact.title}
                                onChange={(e) => updateContact({ title: e.target.value })}
                            />
                        </div>
                        <div className="form-group">
                            <label className="form-label">Address</label>
                            <textarea
                                className="form-input"
                                rows={4}
                                value={data.contact.address}
                                onChange={(e) => updateContact({ address: e.target.value })}
                                placeholder="Use \n for line breaks"
                            />
                        </div>
                        <div className="form-grid-2">
                            <div className="form-group">
                                <label className="form-label">Phone</label>
                                <input
                                    type="text"
                                    className="form-input"
                                    value={data.contact.phone}
                                    onChange={(e) => updateContact({ phone: e.target.value })}
                                />
                            </div>
                            <div className="form-group">
                                <label className="form-label">Email</label>
                                <input
                                    type="text"
                                    className="form-input"
                                    value={data.contact.email}
                                    onChange={(e) => updateContact({ email: e.target.value })}
                                />
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'links' && (
                    <div className="tab-content fadeIn">
                        <div className="form-group">
                            <label className="form-label">Section Title</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.quickLinks.title}
                                onChange={(e) => onChange({ quickLinks: { ...data.quickLinks, title: e.target.value } })}
                            />
                        </div>
                        <div className="links-editor-list">
                            <div className="sub-section-header">
                                <h4>Manage Links</h4>
                                <button className="btn-mini-add" onClick={addQuickLink}>+ Add Link</button>
                            </div>
                            {data.quickLinks.items.map((item) => (
                                <div key={item.id} className="footer-link-edit-row">
                                    <input
                                        type="text"
                                        className="form-input mini"
                                        placeholder="Label"
                                        value={item.label}
                                        onChange={(e) => updateQuickLink(item.id, { label: e.target.value })}
                                    />
                                    <input
                                        type="text"
                                        className="form-input mini"
                                        placeholder="URL"
                                        value={item.href || ''}
                                        onChange={(e) => updateQuickLink(item.id, { href: e.target.value })}
                                    />
                                    <button className="btn-mini-delete-icon" onClick={() => removeQuickLink(item.id)} title="Delete Link">
                                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                            <polyline points="3 6 5 6 21 6"></polyline>
                                            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                        </svg>
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {activeTab === 'social' && (
                    <div className="tab-content fadeIn">
                        <div className="form-group">
                            <label className="form-label">Section Title</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.social.title}
                                onChange={(e) => updateSocial({ title: e.target.value })}
                            />
                        </div>
                        <div className="form-group">
                            <label className="form-label">YouTube URL</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.social.youtube || ''}
                                onChange={(e) => updateSocial({ youtube: e.target.value })}
                            />
                        </div>
                        <div className="form-group">
                            <label className="form-label">Facebook URL</label>
                            <input
                                type="text"
                                className="form-input"
                                value={data.social.facebook || ''}
                                onChange={(e) => updateSocial({ facebook: e.target.value })}
                            />
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

export default FooterEditor
