import React from 'react'
import './GhiDanhNhapHocEditor.css' // Reusing established styles for consistency
import { GhiDanhThienContent } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import SectionLockControl from './SectionLockControl'
import { useFormData } from '../../hooks/useFormData'
import FormRenderer from '../FormBuilder/FormRenderer'
import '../FormBuilder/FormRenderer.css'

type GhiDanhThienEditorProps = {
    data: GhiDanhThienContent
    onChange: (data: Partial<GhiDanhThienContent>) => void
    onNavigate?: (page: any) => void
}

const GhiDanhThienEditor: React.FC<GhiDanhThienEditorProps> = ({ data, onChange, onNavigate }) => {

    const { forms } = useFormData();
    const selectedForm = forms.find(f => f.id === data.formId);

    // Auto-sync form snippet if it's stale (MTC-BDPQ-035)
    React.useEffect(() => {
        if (data.formId && selectedForm) {
            const currentSnippetStr = JSON.stringify(data.form);
            const masterStr = JSON.stringify(selectedForm);
            if (currentSnippetStr !== masterStr) {
                console.log('[CMS][SYNC] Form snapshot is stale, updating draft...');
                onChange({ form: selectedForm });
            }
        }
    }, [data.formId, selectedForm, data.form, onChange]);

    const handleFormSelect = (formId: string) => {
        const fullForm = forms.find(f => f.id === formId);
        onChange({ formId, form: fullForm });
    };

    return (
        <div className="ghi-danh-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Ghi Danh Thiền (Page 3)</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Update registration form fields and section content</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                {/* General Content */}
                <div className="editor-section">
                    <div className="editor-section-title">General Information</div>
                    <div className="form-group">
                        <label className="form-label">Section Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                    </div>
                    <ImageEditor
                        label="Desktop Featured Image"
                        hint="The large image shown on the left side of the form on desktop"
                        value={data.desktopImage}
                        onChange={(val) => onChange({ desktopImage: val })}
                        aspectRatio="portrait"
                    />
                    <div className="form-group">
                        <label className="form-label">Submit Button Label</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.submitLabel}
                            onChange={(e) => onChange({ submitLabel: e.target.value })}
                        />
                    </div>
                </div>

                {/* Form Selection */}
                <div className="editor-section">
                    <div className="editor-section-title">Form Selection</div>
                    <div className="form-group">
                        <label className="form-label">Select Form from Form Builder</label>
                        <div style={{ display: 'flex', gap: '1rem', alignItems: 'center', marginBottom: '1rem' }}>
                            <select
                                className="form-input"
                                value={data.formId || ''}
                                onChange={(e) => handleFormSelect(e.target.value)}
                                style={{ flex: 1 }}
                            >
                                <option value="">-- Choose a Form --</option>
                                {forms.map(form => (
                                    <option key={form.id} value={form.id}>{form.title}</option>
                                ))}
                            </select>
                            <button
                                onClick={() => onNavigate?.('form_builder')}
                                className="btn-secondary"
                                style={{
                                    textDecoration: 'none',
                                    padding: '8px 12px',
                                    backgroundColor: '#f3f4f6',
                                    border: '1px solid #d1d5db',
                                    borderRadius: '4px',
                                    fontSize: '14px',
                                    color: '#374151',
                                    cursor: 'pointer'
                                }}
                            >
                                Open Form Builder
                            </button>
                        </div>

                        {selectedForm ? (
                            <div className="form-preview-container" style={{
                                padding: '1.5rem',
                                border: '1px solid #e5e7eb',
                                borderRadius: '8px',
                                backgroundColor: '#f9fafb'
                            }}>
                                <h4 style={{ marginTop: 0, marginBottom: '1rem', color: '#6b7280', fontSize: '12px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                                    Preview (Read Only)
                                </h4>
                                <FormRenderer form={selectedForm} disabled={true} />
                            </div>
                        ) : (
                            <div style={{
                                padding: '2rem',
                                textAlign: 'center',
                                border: '1px dashed #d1d5db',
                                borderRadius: '8px',
                                color: '#9ca3af'
                            }}>
                                Select a form to see preview
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    )
}

export default GhiDanhThienEditor
