import React from "react"
import "./ChuongTrinhSoTrungDangEditor.css"
import { ChuongTrinhSoTrungDangContent } from "../../contexts/types"
import ImageEditor from "./ImageEditor"
import SectionLockControl from './SectionLockControl'

type Props = {
  data: ChuongTrinhSoTrungDangContent
  onChange: (data: Partial<ChuongTrinhSoTrungDangContent>) => void
}

const ChuongTrinhSoTrungDangEditor: React.FC<Props> = ({ data, onChange }) => {

  const updateMeta = (key: "duration" | "schedule", value: any) => {
    onChange({
      meta: {
        ...data.meta,
        [key]: value
      }
    })
  }

  const updateCurriculum = (side: "left" | "right", index: number, value: string) => {
    const updated = [...data.curriculum[side]]
    updated[index] = value

    onChange({
      curriculum: {
        ...data.curriculum,
        [side]: updated
      }
    })
  }

  const addCurriculumItem = (side: "left" | "right") => {
    onChange({
      curriculum: {
        ...data.curriculum,
        [side]: [...data.curriculum[side], ""]
      }
    })
  }

  const removeCurriculumItem = (side: "left" | "right", index: number) => {
    onChange({
      curriculum: {
        ...data.curriculum,
        [side]: data.curriculum[side].filter((_, i) => i !== index)
      }
    })
  }

  return (
    <div className="ct-editor">
      <div className="editor-header-title">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h2>Edit Chương Trình Sơ Trung Đẳng</h2>
          <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
        </div>
        <p className="editor-subtitle">
          Update program content, schedule and curriculum
        </p>
      </div>

      <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>

        {/* GENERAL */}
        <div className="editor-section">
          <div className="editor-section-title">General Content</div>

          <div className="form-group">
            <label className="form-label">Section Title</label>
            <input
              className={`form-input ${data.title.length > 80 ? 'input-error' : ''}`}
              value={data.title}
              onChange={(e) => onChange({ title: e.target.value })}
            />
            <div className="input-counter">
              <span className={data.title.length > 80 ? 'text-danger' : ''}>
                {data.title.length}/80
              </span>
            </div>
          </div>

          <ImageEditor
            label="Featured Image"
            hint="Left-side image on desktop"
            value={data.image.src}
            onChange={(val) =>
              onChange({
                image: { ...data.image, src: val }
              })
            }
            aspectRatio="portrait"
          />

          <div className="form-group" style={{ marginTop: '1rem' }}>
            <label className="form-label">Image Position (Desktop)</label>
            <div className="radio-group" style={{ display: 'flex', gap: '1.5rem' }}>
              <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                <input
                  type="radio"
                  name="ct-img-pos"
                  checked={!data.imagePosition || data.imagePosition === 'left'}
                  onChange={() => onChange({ imagePosition: 'left' })}
                />
                Image Left (default)
              </label>
              <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                <input
                  type="radio"
                  name="ct-img-pos"
                  checked={data.imagePosition === 'right'}
                  onChange={() => onChange({ imagePosition: 'right' })}
                />
                Image Right
              </label>
            </div>
          </div>
        </div>

        {/* META */}
        <div className="editor-section">
          <div className="editor-section-title">Program Information</div>

          <div className="form-group">
            <label className="form-label">Duration</label>
            <input
              className={`form-input ${data.meta.duration.length > 60 ? 'input-error' : ''}`}
              value={data.meta.duration}
              onChange={(e) => updateMeta("duration", e.target.value)}
            />
            <div className="input-counter">
              <span className={data.meta.duration.length > 60 ? 'text-danger' : ''}>
                {data.meta.duration.length}/60
              </span>
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">Schedule</label>
            <div className="options-list">
              {data.meta.schedule.map((line, i) => (
                <div key={i} className="option-item-group">
                  <div className="option-item">
                    <input
                      className={`form-input ${line.length > 100 ? 'input-error' : ''}`}
                      value={line}
                      onChange={(e) => {
                        const updated = [...data.meta.schedule]
                        updated[i] = e.target.value
                        updateMeta("schedule", updated)
                      }}
                    />
                    <button
                      className="btn-remove"
                      onClick={() => {
                        if (window.confirm('Delete this schedule line?')) {
                          updateMeta(
                            "schedule",
                            data.meta.schedule.filter((_, idx) => idx !== i)
                          )
                        }
                      }}
                      title="Delete Schedule Line"
                    >
                      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <polyline points="3 6 5 6 21 6"></polyline>
                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                      </svg>
                    </button>
                  </div>
                  <div className="input-counter">
                    <span className={line.length > 100 ? 'text-danger' : ''}>
                      {line.length}/100
                    </span>
                  </div>
                </div>
              ))}
              <button
                className="btn-add"
                onClick={() => updateMeta("schedule", [...data.meta.schedule, ""])}
              >
                + Add Schedule Line
              </button>
            </div>
          </div>
        </div>

        {/* CURRICULUM */}
        <div className="editor-section">
          <div className="editor-section-title">Curriculum</div>

          <div className="field-grid">

            {/* LEFT */}
            <div>
              <label className="form-label">Left Column</label>
              <div className="options-list">
                {data.curriculum.left.map((item, i) => (
                  <div key={i} className="option-item-group">
                    <div className="option-item">
                      <input
                        className={`form-input ${item.length > 100 ? 'input-error' : ''}`}
                        value={item}
                        onChange={(e) =>
                          updateCurriculum("left", i, e.target.value)
                        }
                      />
                      <button
                        className="btn-remove"
                        onClick={() => removeCurriculumItem("left", i)}
                      >
                        ×
                      </button>
                    </div>
                    <div className="input-counter">
                      <span className={item.length > 100 ? 'text-danger' : ''}>
                        {item.length}/100
                      </span>
                    </div>
                  </div>
                ))}
                <button
                  className="btn-add"
                  onClick={() => addCurriculumItem("left")}
                >
                  + Add Item
                </button>
              </div>
            </div>

            {/* RIGHT */}
            <div>
              <label className="form-label">Right Column</label>
              <div className="options-list">
                {data.curriculum.right.map((item, i) => (
                  <div key={i} className="option-item-group">
                    <div className="option-item">
                      <input
                        className={`form-input ${item.length > 100 ? 'input-error' : ''}`}
                        value={item}
                        onChange={(e) =>
                          updateCurriculum("right", i, e.target.value)
                        }
                      />
                      <button
                        className="btn-remove"
                        onClick={() => removeCurriculumItem("right", i)}
                      >
                        ×
                      </button>
                    </div>
                    <div className="input-counter">
                      <span className={item.length > 100 ? 'text-danger' : ''}>
                        {item.length}/100
                      </span>
                    </div>
                  </div>
                ))}
                <button
                  className="btn-add"
                  onClick={() => addCurriculumItem("right")}
                >
                  + Add Item
                </button>
              </div>
            </div>

          </div>
        </div>

      </div>
    </div>
  )
}

export default ChuongTrinhSoTrungDangEditor
