import React, { useRef, useState } from 'react'
import './ImageEditor.css'
import ImageUploadModal from '../modals/ImageUploadModal'

type ImageEditorProps = {
    label: string
    hint?: string
    value: string
    onChange: (value: string) => void
    placeholder?: string
    aspectRatio?: 'landscape' | 'logo' | 'square' | 'portrait'
    compact?: boolean
}

const ImageEditor: React.FC<ImageEditorProps> = ({
    label,
    hint,
    value,
    onChange,
    placeholder = "Paste image URL here...",
    aspectRatio = 'landscape',
    compact = false
}) => {
    const [isModalOpen, setIsModalOpen] = useState(false)
    const inputRef = useRef<HTMLInputElement>(null)

    const handleEditClick = () => {
        setIsModalOpen(true)
    }

    const handleUpload = (newUrl: string) => {
        onChange(newUrl)
    }

    return (
        <div className={`image-editor-component ${compact ? 'compact' : ''}`}>
            <label className="form-label">
                {label}
                {hint && <span className="label-hint">{hint}</span>}
            </label>

            <div className={`image-workspace ${aspectRatio}-ratio ${compact ? 'compact-workspace' : ''}`}>
                {value ? (
                    <div className="image-current-wrapper">
                        <img src={value} alt="Preview" className="image-current-preview" />
                        <div className="image-overlay-actions">
                            <button className="btn-edit-image" onClick={handleEditClick} type="button">
                                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" />
                                    <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" />
                                </svg>
                                {!compact && "Edit Image"}
                            </button>
                        </div>
                    </div>
                ) : (
                    <div className="image-upload-placeholder" onClick={handleEditClick}>
                        <svg width={compact ? 24 : 48} height={compact ? 24 : 48} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round">
                            <rect width="18" height="18" x="3" y="3" rx="2" ry="2" />
                            <circle cx="9" cy="9" r="2" />
                            <path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21" />
                        </svg>
                        {!compact && (
                            <>
                                <p>Click to add image</p>
                                <span>Supports: JPG, PNG, WEBP, SVG</span>
                            </>
                        )}
                    </div>
                )}

                {!compact && (
                    <div className="image-url-input-group">
                        <div className="input-with-icon">
                            <svg className="input-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 0 0 0-7.07-7.07l-1.72 1.71" />
                                <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 0 0 0 7.07 7.07l1.71-1.71" />
                            </svg>
                            <input
                                ref={inputRef}
                                type="text"
                                className="form-input"
                                value={value}
                                readOnly
                                onClick={handleEditClick}
                                placeholder={placeholder}
                            />
                        </div>
                    </div>
                )}
            </div>

            <ImageUploadModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onUpload={handleUpload}
                currentValue={value}
            />
        </div>
    )
}

export default ImageEditor
