import React, { useState, useEffect } from 'react';
import './FormBuilderEditor.css';
import { useFormData } from '../../hooks/useFormData';
import { FormField, Form } from '../ppm/cms/form-builder/FormBuilderTypes';
import PopupDynamic from '../modals/PopupDynamic';
import { useCMS } from '../../contexts/CMSContext';
import SectionLockControl from './SectionLockControl';

const FIELD_TYPES = [
    { value: 'short_answer', label: 'Short Answer' },
    { value: 'paragraph', label: 'Paragraph' },
    { value: 'multiple_choice', label: 'Multiple Choice' },
    { value: 'dropdown', label: 'Dropdown' },
    { value: 'checkboxes', label: 'Checkboxes' },
    { value: 'linear_scale', label: 'Linear Scale' },
    { value: 'file_upload', label: 'File Upload' },
    { value: 'date', label: 'Date' },
    { value: 'time', label: 'Time' },
];

const TEMPLATES = [
    { id: 'blank', label: 'Blank Form', fields: [] },
    {
        id: 'contact',
        label: 'Sample Contact Form',
        fields: [
            { id: 'f1', name: 'Email Address', type: 'short_answer', required: true, validation: { mode: 'email' } },
            { id: 'f2', name: 'Message', type: 'paragraph', required: false }
        ]
    }
];

interface FormBuilderEditorProps {
    showNotification: (message: string, type?: 'success' | 'error' | 'info') => void;
}

const FormBuilderEditor: React.FC<FormBuilderEditorProps> = ({ showNotification }) => {
    const {
        forms,
        loading,
        createForm,
        updateForm,
        deleteForm
    } = useFormData();

    // activeFormId matches a saved form ID. Null if we are editing a new unsaved form.
    const [activeFormId, setActiveFormId] = useState<string | null>(null);

    // draftForm holds the current state of the editor.
    const [draftForm, setDraftForm] = useState<Form | null>(null);

    const [showTemplateMenu, setShowTemplateMenu] = useState(false);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

    // Sync draft with active form selection from sidebar
    useEffect(() => {
        if (activeFormId) {
            const found = forms.find(f => f.id === activeFormId);
            if (found) {
                // Load existing form into draft
                // Deep copy to ensure we don't mutate state directly
                setDraftForm(JSON.parse(JSON.stringify(found)));
            } else {
                // If ID is stale (form deleted), reset
                setActiveFormId(null);
                setDraftForm(null);
            }
        }
    }, [activeFormId, forms]);

    const handleCreateForm = () => {
        // Initialize a new blank draft. Do NOT create in DB yet.
        const newDraft: Form = {
            id: `temp_${Date.now()}`,
            title: 'New Form',
            fields: []
        };
        setActiveFormId(null);
        setDraftForm(newDraft);
        setShowTemplateMenu(false);
    };

    const handleLoadTemplate = (templateId: string) => {
        const template = TEMPLATES.find(t => t.id === templateId);
        // If blank template selected, just do create form logic
        if (templateId === 'blank') {
            handleCreateForm();
            return;
        }

        if (template) {
            // Initialize draft from template. Do NOT create in DB yet.
            const newDraft: Form = {
                id: `temp_${Date.now()}`,
                title: template.label,
                fields: JSON.parse(JSON.stringify(template.fields))
            };
            setActiveFormId(null);
            setDraftForm(newDraft);
        }
        setShowTemplateMenu(false);
    };

    const { updateGhiDanhNhapHocContent } = useCMS();

    const handleSaveForm = () => {
        if (!draftForm) return;

        if (activeFormId) {
            // Update existing form
            updateForm(activeFormId, draftForm);
        } else {
            // Create new form
            const created = createForm(draftForm.title, draftForm.fields);
            // Switch to the newly created form ID so future saves are updates
            setActiveFormId(created.id);
        }

        // Trigger CMS Dirty state so "Save Draft" becomes active
        updateGhiDanhNhapHocContent({});

        // Trigger live refresh event
        window.dispatchEvent(new CustomEvent('sbu-cms-re-resolve'));

        showNotification('Form saved successfully!', 'success');
    };

    const handleRenameForm = (newTitle: string) => {
        if (!draftForm) return;
        setDraftForm({ ...draftForm, title: newTitle });
    };

    const handleAddField = () => {
        if (!draftForm) return;
        const newField: FormField = {
            id: `field_${Date.now()}`,
            name: 'New Question',
            type: 'short_answer',
            required: false,
            helpText: ''
        };
        setDraftForm({
            ...draftForm,
            fields: [...draftForm.fields, newField]
        });
    };

    const handleUpdateField = (fieldId: string, updates: Partial<FormField>) => {
        if (!draftForm) return;
        const updatedFields = draftForm.fields.map(f =>
            f.id === fieldId ? { ...f, ...updates } : f
        ) as FormField[];
        setDraftForm({ ...draftForm, fields: updatedFields });
    };

    const handleRemoveField = (fieldId: string) => {
        if (!draftForm) return;
        const updatedFields = draftForm.fields.filter(f => f.id !== fieldId);
        setDraftForm({ ...draftForm, fields: updatedFields });
    };

    const handleDeleteActiveForm = () => {
        if (activeFormId) {
            deleteForm(activeFormId);
            setActiveFormId(null);
            setDraftForm(null);
            setShowDeleteConfirm(false);
        }
    };

    if (loading) {
        return (
            <div className="form-builder-container">
                <div className="workspace-empty-state">
                    <p>Loading forms...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="form-builder-container">
            {/* Sidebar - List of Forms */}
            <aside className="form-builder-sidebar">
                <div className="sidebar-header">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                        <h3 style={{ margin: 0 }}>My Forms</h3>
                        <div style={{ position: 'relative' }}>
                            <button
                                className="btn-secondary"
                                style={{ padding: '4px 8px', fontSize: '12px', cursor: 'pointer', background: '#f3f4f6', border: '1px solid #d1d5db', borderRadius: '4px' }}
                                onClick={() => setShowTemplateMenu(!showTemplateMenu)}
                            >
                                Templates ▾
                            </button>
                            {showTemplateMenu && (
                                <div style={{
                                    position: 'absolute',
                                    top: '100%',
                                    right: 0,
                                    background: 'white',
                                    border: '1px solid #e5e7eb',
                                    borderRadius: '6px',
                                    boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)',
                                    zIndex: 10,
                                    width: '180px',
                                    padding: '4px'
                                }}>
                                    {TEMPLATES.map(t => (
                                        <button
                                            key={t.id}
                                            style={{
                                                width: '100%',
                                                textAlign: 'left',
                                                padding: '8px',
                                                background: 'none',
                                                border: 'none',
                                                fontSize: '13px',
                                                cursor: 'pointer',
                                                borderRadius: '4px'
                                            }}
                                            onMouseOver={(e) => e.currentTarget.style.background = '#f3f4f6'}
                                            onMouseOut={(e) => e.currentTarget.style.background = 'none'}
                                            onClick={() => handleLoadTemplate(t.id)}
                                        >
                                            {t.label}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                    {/* The Sidebar Create Form button initializes a blank draft */}
                    <button className="btn-create-form" onClick={handleCreateForm}>
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                            <line x1="12" y1="5" x2="12" y2="19"></line>
                            <line x1="5" y1="12" x2="19" y2="12"></line>
                        </svg>
                        Create Form
                    </button>
                </div>
                <div className="form-list">
                    {forms.map(form => (
                        <div
                            key={form.id}
                            className={`form-list-item ${activeFormId === form.id ? 'active' : ''}`}
                            onClick={() => setActiveFormId(form.id)}
                        >
                            <span className="form-item-title">{form.title}</span>
                            <div className="form-item-badge">{form.fields.length} fields</div>
                        </div>
                    ))}
                    {forms.length === 0 && (
                        <p style={{ textAlign: 'center', color: '#9ca3af', fontSize: '0.875rem', marginTop: '2rem' }}>
                            No forms created yet.
                        </p>
                    )}
                </div>
            </aside>

            {/* Main Workspace - Form Editor */}
            <main className="form-builder-workspace">
                {draftForm ? (
                    <div style={{ width: '100%', maxWidth: '800px' }}>
                        <div className="form-editor-card">
                            <div className="form-editor-header">
                                <input
                                    className="form-title-input"
                                    value={draftForm.title}
                                    onChange={(e) => handleRenameForm(e.target.value)}
                                    placeholder="Enter form title..."
                                    disabled={!!draftForm.locked}
                                />
                                <div style={{ marginRight: '1rem' }}>
                                    <SectionLockControl
                                        locked={draftForm.locked}
                                        onToggle={(locked) => setDraftForm({ ...draftForm, locked })}
                                    />
                                </div>
                                <div className="form-actions" style={{ display: 'flex', alignItems: 'center' }}>
                                    {/* SAVE FORM BUTTON */}
                                    <button
                                        onClick={handleSaveForm}
                                        style={{
                                            background: '#10b981',
                                            color: 'white',
                                            border: 'none',
                                            padding: '8px 16px',
                                            borderRadius: '6px',
                                            fontWeight: 500,
                                            fontSize: '14px',
                                            cursor: 'pointer',
                                            display: 'flex',
                                            alignItems: 'center',
                                            gap: '6px',
                                            marginRight: '8px',
                                            boxShadow: '0 1px 2px rgba(0,0,0,0.05)'
                                        }}
                                        onMouseOver={(e) => e.currentTarget.style.background = '#059669'}
                                        onMouseOut={(e) => e.currentTarget.style.background = '#10b981'}
                                    >
                                        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                            <path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"></path>
                                            <polyline points="17 21 17 13 7 13 7 21"></polyline>
                                            <polyline points="7 3 7 8 15 8"></polyline>
                                        </svg>
                                        Save Form
                                    </button>

                                    {/* DELETE BUTTON - Only show if we are editing an already saved form */}
                                    {activeFormId && (
                                        <button
                                            className="btn-delete-form"
                                            onClick={() => setShowDeleteConfirm(true)}
                                        >
                                            Delete Form
                                        </button>
                                    )}
                                </div>
                            </div>

                            <div className="fields-container" style={{
                                opacity: draftForm.locked ? 0.6 : 1,
                                pointerEvents: draftForm.locked ? 'none' : 'auto',
                                transition: 'opacity 0.3s'
                            }}>
                                {draftForm.fields.length === 0 && (
                                    <div style={{ textAlign: 'center', padding: '3rem 1rem', color: '#6b7280' }}>
                                        <p style={{ fontSize: '1.125rem', fontWeight: 500 }}>Empty Form</p>
                                        <p style={{ fontSize: '0.875rem' }}>Click "Add Field" below to begin building your form.</p>
                                    </div>
                                )}

                                {draftForm.fields.map((field) => (
                                    <div key={field.id} className="field-block">
                                        <div className="field-row">
                                            <div className="field-input-group">
                                                <label className="field-label">Question name</label>
                                                <input
                                                    className="input-standard"
                                                    value={field.name}
                                                    onChange={(e) => handleUpdateField(field.id, { name: e.target.value })}
                                                    placeholder="e.g. Email Address"
                                                />
                                            </div>
                                            <div className="field-input-group">
                                                <label className="field-label">Field Type</label>
                                                <select
                                                    className="input-standard"
                                                    value={field.type}
                                                    onChange={(e) => {
                                                        const newType = e.target.value as any;
                                                        const updates: any = { type: newType };

                                                        // Initialize options if switching to a choice type and they don't exist
                                                        if (['multiple_choice', 'dropdown', 'checkboxes'].includes(newType) && !(field as any).options) {
                                                            updates.options = ['Option 1'];
                                                        }

                                                        handleUpdateField(field.id, updates);
                                                    }}
                                                >
                                                    {FIELD_TYPES.map(type => (
                                                        <option key={type.value} value={type.value}>
                                                            {type.label}
                                                        </option>
                                                    ))}
                                                </select>
                                            </div>
                                            <button
                                                className="btn-delete-field"
                                                onClick={() => handleRemoveField(field.id)}
                                                title="Remove field"
                                            >
                                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                    <polyline points="3 6 5 6 21 6"></polyline>
                                                    <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                </svg>
                                            </button>
                                        </div>

                                        {/* Placeholder for complex types */}
                                        {['linear_scale', 'file_upload'].includes(field.type) && (
                                            <div style={{ marginTop: '1rem', padding: '0.75rem', background: '#f8f9fa', borderRadius: '6px', fontSize: '13px', color: '#6b7280', border: '1px dashed #d1d5db' }}>
                                                {field.type === 'linear_scale' ? 'Linear scale field (configure later)' : 'File upload field (configure later)'}
                                            </div>
                                        )}

                                        {/* Options Editor for Choice Fields */}
                                        {['multiple_choice', 'dropdown', 'checkboxes'].includes(field.type) && (
                                            <div className="field-options-editor" style={{ marginTop: '1.25rem', paddingLeft: '1rem', borderLeft: '3px solid #e5e7eb' }}>
                                                <label className="field-label" style={{ marginBottom: '0.75rem', display: 'block' }}>Options</label>
                                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                                    {((field as any).options || []).map((option: string, idx: number) => (
                                                        <div key={idx} style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                                                            <div style={{ color: '#9ca3af', fontSize: '12px' }}>{idx + 1}.</div>
                                                            <input
                                                                className="input-standard"
                                                                style={{ padding: '6px 10px', height: '36px' }}
                                                                value={option}
                                                                onChange={(e) => {
                                                                    const newOpts = [...(field as any).options];
                                                                    newOpts[idx] = e.target.value;
                                                                    handleUpdateField(field.id, { options: newOpts });
                                                                }}
                                                                placeholder={`Option ${idx + 1}`}
                                                            />
                                                            <button
                                                                onClick={() => {
                                                                    const newOpts = (field as any).options.filter((_: any, i: number) => i !== idx);
                                                                    handleUpdateField(field.id, { options: newOpts });
                                                                }}
                                                                style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '4px' }}
                                                            >
                                                                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                    <line x1="18" y1="6" x2="6" y2="18"></line>
                                                                    <line x1="6" y1="6" x2="18" y2="18"></line>
                                                                </svg>
                                                            </button>
                                                        </div>
                                                    ))}
                                                    <button
                                                        onClick={() => {
                                                            const currentOpts = (field as any).options || [];
                                                            handleUpdateField(field.id, { options: [...currentOpts, `Option ${currentOpts.length + 1}`] });
                                                        }}
                                                        style={{
                                                            alignSelf: 'flex-start',
                                                            background: 'none',
                                                            border: 'none',
                                                            color: '#3b82f6',
                                                            fontSize: '13px',
                                                            fontWeight: 500,
                                                            cursor: 'pointer',
                                                            display: 'flex',
                                                            alignItems: 'center',
                                                            gap: '4px',
                                                            padding: '4px 8px',
                                                            marginTop: '4px'
                                                        }}
                                                    >
                                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                                            <line x1="12" y1="5" x2="12" y2="19"></line>
                                                            <line x1="5" y1="12" x2="19" y2="12"></line>
                                                        </svg>
                                                        Add Option
                                                    </button>
                                                </div>
                                            </div>
                                        )}

                                        <div className="field-footer-row" style={{ marginTop: '1.25rem' }}>
                                            <div className="field-input-group" style={{ flex: 1 }}>
                                                <label className="field-label">Placeholder (Optional)</label>
                                                <input
                                                    className="input-standard"
                                                    value={field.placeholder || ''}
                                                    onChange={(e) => handleUpdateField(field.id, { placeholder: e.target.value })}
                                                    placeholder="Gray text inside input..."
                                                />
                                            </div>
                                            <div className="field-input-group" style={{ flex: 1 }}>
                                                <label className="field-label">Help Text</label>
                                                <input
                                                    className="input-standard input-help-text"
                                                    value={field.helpText || ''}
                                                    onChange={(e) => handleUpdateField(field.id, { helpText: e.target.value })}
                                                    placeholder="Instruction for users..."
                                                />
                                            </div>
                                            <label className="field-required-label">
                                                <input
                                                    type="checkbox"
                                                    checked={!!field.required}
                                                    onChange={(e) => handleUpdateField(field.id, { required: e.target.checked })}
                                                />
                                                <span>Required</span>
                                            </label>
                                        </div>
                                    </div>
                                ))}

                                <div className="add-field-footer">
                                    <button className="btn-add-field" onClick={handleAddField}>
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <line x1="12" y1="5" x2="12" y2="19"></line>
                                            <line x1="5" y1="12" x2="19" y2="12"></line>
                                        </svg>
                                        Add Field
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="workspace-empty-state">
                        <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round" opacity="0.3" style={{ marginBottom: '1.5rem' }}>
                            <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                            <polyline points="14 2 14 8 20 8"></polyline>
                            <line x1="9" y1="15" x2="15" y2="15"></line>
                            <line x1="9" y1="11" x2="15" y2="11"></line>
                            <line x1="9" y1="19" x2="12" y2="19"></line>
                        </svg>
                        <h2>Form Builder</h2>
                        <p>Select an existing form from the sidebar or click "Create Form" to get started.</p>
                    </div>
                )}
            </main>

            <PopupDynamic
                isOpen={showDeleteConfirm}
                onClose={() => setShowDeleteConfirm(false)}
                title="Delete Form?"
                subtitle={`Are you sure you want to delete "${draftForm?.title}"? This will permanently remove the form and all its fields. This action cannot be undone.`}
                type="error"
                buttons={[
                    {
                        buttonText: "Yes, Delete Form",
                        buttonTextActive: "Deleting...",
                        buttonTextResponse: "Deleted!",
                        variant: "danger",
                        onClick: async () => handleDeleteActiveForm()
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setShowDeleteConfirm(false)
                    }
                ]}
            />
        </div>
    );
};

export default FormBuilderEditor;
